const { open, readdir } = require("node:fs/promises");
const os = require("node:os");
const path = require("node:path");
const { pathToFileURL } = require("node:url");

const PLUGIN_NAME = "claude-interrogate";
const SERVER_MARKER = "claude-interrogate MCP server";

function unique(values) {
  return Array.from(new Set(values));
}

async function readPrefix(filePath, maxBytes) {
  const handle = await open(filePath, "r");
  try {
    const buffer = Buffer.alloc(maxBytes);
    const result = await handle.read(buffer, 0, maxBytes, 0);
    return buffer.subarray(0, result.bytesRead).toString("utf8");
  } finally {
    await handle.close();
  }
}

async function listSubdirs(dirPath) {
  try {
    const entries = await readdir(dirPath, { withFileTypes: true });
    return entries.filter((e) => e.isDirectory()).map((e) => e.name);
  } catch {
    return [];
  }
}

async function findFromCodexCache() {
  const codexHome = process.env.CODEX_HOME || path.join(os.homedir(), ".codex");
  const cacheRoot = path.join(codexHome, "plugins", "cache");

  const marketplaceDirs = await listSubdirs(cacheRoot);
  for (const marketplace of marketplaceDirs) {
    const pluginDir = path.join(cacheRoot, marketplace, PLUGIN_NAME);
    const versionDirs = await listSubdirs(pluginDir);

    const sortedVersions = versionDirs.slice().sort((a, b) => {
      if (a === "local" && b !== "local") return -1;
      if (b === "local" && a !== "local") return 1;
      return b.localeCompare(a);
    });

    for (const version of sortedVersions) {
      const serverPath = path.join(pluginDir, version, "runtime", "dist", "server.js");
      try {
        const prefix = await readPrefix(serverPath, 4096);
        if (!prefix.includes(SERVER_MARKER)) {
          continue;
        }
        return serverPath;
      } catch {
        // continue
      }
    }
  }

  return undefined;
}

(async () => {
  const candidates = [];

  for (const root of unique(
    [
      process.env.CLAUDE_PLUGIN_ROOT,
      process.env.CODEX_PLUGIN_ROOT,
      process.env.PLUGIN_ROOT,
    ].filter(Boolean),
  )) {
    candidates.push(path.join(root, "runtime", "dist", "server.js"));
  }

  const cacheServerPath = await findFromCodexCache();
  if (cacheServerPath) {
    candidates.push(cacheServerPath);
  }

  candidates.push(path.resolve("runtime", "dist", "server.js"));

  let serverPath;
  for (const candidate of unique(candidates)) {
    try {
      const prefix = await readPrefix(candidate, 4096);
      if (!prefix.includes(SERVER_MARKER)) {
        continue;
      }
      serverPath = candidate;
      break;
    } catch {
      // continue
    }
  }

  if (!serverPath) {
    throw new Error(
      [
        "Could not locate claude-interrogate runtime/dist/server.js",
        "cwd: " + process.cwd(),
        "checked: " + unique(candidates).join(", "),
      ].join("\n"),
    );
  }

  const pluginRoot = path.dirname(path.dirname(path.dirname(serverPath)));
  try {
    process.chdir(pluginRoot);
  } catch {
    // ignore
  }
  process.argv = [process.argv[0], serverPath];

  await import(pathToFileURL(serverPath).href);
})().catch((error) => {
  console.error(error instanceof Error ? error.stack || error.message : String(error));
  process.exit(1);
});
